class Solution {
    public long repairCars(int[] ranks, int cars) {
        Arrays.sort(ranks);
        long low = 1, high = (long) 1e18, ans = 0;
        while (low <= high) {
            long mid = low + (high - low) / 2;
            long sum = 0;
            for (int rank : ranks) {
                sum += Math.min(mid / rank, cars);
            }
            if (sum >= cars) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
}
